type BannerCarouselProps = {
  bannersCarousels: [
    {
      img: string;
    }
  ];
};

export const BannerCarousel: React.FC<BannerCarouselProps> = ({
  bannersCarousels,
}: BannerCarouselProps) => {
  return (
    <>
      <Carousel {...settings}>
        {bannersCarousels?.map(({ img }, index) => {
          return (
            <Carousel.Item key={index}>
              <img
                src={img}
                className="h-[500px] w-full object-cover mb-0 mx-auto text-center"
              />
            </Carousel.Item>
          );
        })}
      </Carousel>
    </>
  );
};

