type GameCarouselProps = {
  gameCarousels: [
    {
      title: string;
      name: string;
      desc: string;
      img: string;
    }
  ];
};

export const GameCarousel: React.FC<GameCarouselProps> = ({
  gameCarousels,
}: GameCarouselProps) => {
  const preset = {
    dots: false,
    infinite: true,
    speed: 500,
    slidesToShow: 3,
    slidesToScroll: 3,
    adaptiveHeight: true,
    responsive: [
      {
        breakpoint: 1670,
        settings: {
          slidesToShow: 3,
          slidesToScroll: 3,
        },
      },
      {
        breakpoint: 1400,
        settings: {
          slidesToShow: 3,
          slidesToScroll: 3,
        },
      },
      {
        breakpoint: 1030,
        settings: {
          slidesToShow: 2,
          slidesToScroll: 2,
        },
      },
      {
        breakpoint: 693,
        settings: {
          slidesToShow: 1,
          slidesToScroll: 1,
        },
      },
    ],
  };

  return (
    <CarouselSlick {...preset}>
      {gameCarousels?.map(({ title, name, desc, img }, index) => {
        return (
          <div key={index} className="col">
            <div className="bg-[#2a2a2a] rounded-[20px] p-[30px] mx-[15px] flex flex-col items-center text-center">
              <div className="star">
                <i className="fas fa-star text-[#FFC107] text-[16px]"></i>
                <i className="fas fa-star text-[#FFC107] text-[16px]"></i>
                <i className="fas fa-star text-[#FFC107] text-[16px]"></i>
                <i className="fas fa-star text-[#FFC107] text-[16px]"></i>
                <i className="fas fa-star text-[#FFC107] text-[16px]"></i>
              </div>
              <a href="javascript:void(0)">
                <h5 className="text-white font-chakra text-[24px] mt-[25px] mb-[15px]">
                  {title}
                </h5>
              </a>
              <p className="text-white font-chakra text-[18px] leading-[23px]">
                {desc}
              </p>
              <div className="profile">
                <img
                  src={img}
                  alt="image"
                  className="mx-auto mt-[35px] mb-[20px] bg-[#ff9900] w-16 h-16 rounded-[50%]"
                />
                <a href="javascript:void(0)">
                  <h6 className="text-white uppercase font-chakra text-[18px]">
                    {name}
                  </h6>
                </a>
              </div>
            </div>
          </div>
        );
      })}
    </CarouselSlick>
  );
};

